/**
 * Sets the plane normal and distance
 *
 * @param nx normal x-component
 * @param ny normal y-component
 * @param nz normal z-component
 * @param d  distance to origin
 */
public void set(float nx, float ny, float nz, float d) {
    normal.set(nx, ny, nz);
    this.d = d;
}
